qry:select.qry:xquery:
			for $r in table(' 
				SELECT UPPER(SUBSTRING(d_ape_y_nom, 1, 1)) + LOWER(SUBSTRING(d_ape_y_nom, 2, CHARINDEX ( \', \',d_ape_y_nom ))) + UPPER(SUBSTRING(d_ape_y_nom, CHARINDEX (\', \',d_ape_y_nom ) + 2, 1))+ LOWER(SUBSTRING(d_ape_y_nom, CHARINDEX (\', \',d_ape_y_nom ) + 3, (len(d_ape_y_nom) - CHARINDEX (\' \', d_ape_y_nom, CHARINDEX (\', \', d_ape_y_nom))))) as d_ape_y_nom

				, e_numero_legajo
				, n_totsret + n_totnsret + n_totasig as sueldoBruto
				, n_totcont totalContribucion
				, n_totpag totalNeto
				FROM ORG02_ESTRUC_PERS, PER02_PERSONAL_EMP, PER01_PERSONAL, liq25_personal_liq, liq20_tot_liq_per
				WHERE  
				ORG02_ESTRUC_PERS.oi_estructura={%=#PARAM:@oi_estructura%} 
 				AND PER02_PERSONAL_EMP.oi_empresa = {%=#FILTRO:@oi_empresa%}
				AND PER02_PERSONAL_EMP.oi_personal = PER01_PERSONAL.oi_personal 
				AND PER02_PERSONAL_EMP.oi_personal_emp = liq25_personal_liq.oi_personal_emp 
				AND PER02_PERSONAL_EMP.oi_personal_emp = ORG02_ESTRUC_PERS.oi_personal_emp
				AND liq25_personal_liq.oi_tot_liq_pers = liq20_tot_liq_per.oi_tot_liq_per

				{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') {% AND liq25_personal_liq.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id) %}) %} {%  %} %}	
        {%? (#FILTRO:@oi_estructura!='') {% AND ORG02_ESTRUC_PERS.oi_estructura={%=#FILTRO:@oi_estructura %} %} {% AND 1=1%} %}

                {%?(string(#FILTRO:@oi_liquidacion)!='') 
					{% AND liq25_personal_liq.oi_liquidacion in ({%=string(#FILTRO:@oi_liquidacion)%}) %} 
					{% AND 1=1%} 
				%}   
						')/ROWS/ROW

			for $r in table(' 

				SELECT UPPER(SUBSTRING(d_ape_y_nom, 1, 1)) + LOWER(SUBSTRING(d_ape_y_nom, 2, CHARINDEX ( \', \',d_ape_y_nom ))) + UPPER(SUBSTRING(d_ape_y_nom, CHARINDEX (\', \',d_ape_y_nom ) + 2, 1))+ LOWER(SUBSTRING(d_ape_y_nom, CHARINDEX (\', \',d_ape_y_nom ) + 3, (len(d_ape_y_nom) - CHARINDEX (\' \', d_ape_y_nom, CHARINDEX (\', \', d_ape_y_nom))))) as d_ape_y_nom

				, e_numero_legajo
				, n_totsret + n_totnsret + n_totasig as sueldoBruto
				, n_totcont totalContribucion
				, n_totpag totalNeto
				FROM ORG02_ESTRUC_PERS, PER02_PERSONAL_EMP, PER01_PERSONAL, liq25_personal_liq, liq20_tot_liq_per
				WHERE  
				ORG02_ESTRUC_PERS.oi_estructura={%=#PARAM:@oi_estructura%} 
 				AND PER02_PERSONAL_EMP.oi_empresa = {%=#FILTRO:@oi_empresa%}
				AND PER02_PERSONAL_EMP.oi_personal = PER01_PERSONAL.oi_personal 
				AND PER02_PERSONAL_EMP.oi_personal_emp = liq25_personal_liq.oi_personal_emp 
				AND PER02_PERSONAL_EMP.oi_personal_emp = ORG02_ESTRUC_PERS.oi_personal_emp
				AND liq25_personal_liq.oi_tot_liq_pers = liq20_tot_liq_per.oi_tot_liq_per
              {%?(string(#FILTRO:@oi_liquidacion)!='') 
					{% AND liq25_personal_liq.oi_liquidacion in ({%=string(#FILTRO:@oi_liquidacion)%}) %} 
					{% AND 1=1%} 
				%}
				{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') {% AND liq25_personal_liq.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id) %}) %} {%  %} %}	
        {%? (#FILTRO:@oi_estructura!='') {% AND ORG02_ESTRUC_PERS.oi_estructura={%=#FILTRO:@oi_estructura %} %} {% AND 1=1%} %}
')/ROWS/ROW
